import { defineConfig } from 'vitest/config'

export default defineConfig({
  test: {
    include: ['src/**/*.test.ts'],
    env: {
      NODE_ENV: 'test'
    }
  }
})

{
  "name": "starter-nodejs-api",
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "tsx watch src/index.ts",
    "prebuild": "node -e \"process.exit(require('fs').existsSync('./node_modules/.bin/tsc') ? 0 : 1)\" || (echo 'ERROR: devDependencies not installed. Run: npm install (ensure .npmrc include=dev is set)' && exit 1)",
    "build": "tsc",
    "start": "node dist/index.js",
    "test": "vitest run",
    "audit": "npm audit --audit-level=high --omit=dev",
    "test:watch": "vitest"
  },
  "dependencies": {
    "@fastify/compress": "^8.3.1",
    "@fastify/cors": "^11.2.0",
    "@fastify/helmet": "^13.0.2",
    "@fastify/rate-limit": "^10.3.0",
    "@fastify/swagger": "^9.7.0",
    "@fastify/swagger-ui": "^5.2.5",
    "dotenv": "^16.4.5",
    "fastify": "^5.7.2",
    "zod": "^4.3.6"
  },
  "devDependencies": {
    "@types/node": "~25.5.0",
    "tsx": "^4.19.2",
    "typescript": "~6.0.2",
    "vitest": "^4.1.3"
  },
  "engines": {
    "node": ">=22.0.0"
  },
  "overrides": {
    "@fastify/static": "^9.1.1"
  }
}

